---宝物技能图标

---@class LBattleSkillActTreasureIcon
local LBattleSkillActTreasureIcon = classX("LBattleSkillActTreasureIcon", nil)

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActTreasureIcon.Execute(player,effData, playState)
    local effRes = effData.effRes --光效名字
    local playTime = effData.playTime --光效持续时间
    local dissipateTime = effData.dissipateTime --光效消散时间
    local offset = effData.effOffsetStart --偏移

    local _viewMgr = player:GetViewMgr()
    local _atkUnitView = player:GetAtkUnitView()
    local _skillData = player:GetSkillData()

    local effectCtrl = _viewMgr:GetEffectCtrl()
    local effTrans = _viewMgr:GetEffectRootTrans()
    --local pos = Vector3.New(offset.x,offset.y,0)

    local heroData = _atkUnitView:GetHeroData()
    local skillId = _skillData:GetSkillRefId()
    local index = heroData:GetSkillIndex(skillId)
    local side = heroData:GetTeamType()
    local isRight = side == BattleTeamSide.teamB
    local scaleV = isRight and Vector3(-1,1,1) or Vector3(1,1,1)
    local pos = _viewMgr:GetSkillIconPos(side,index)
    pos.y = pos.y + offset.y

    local effect = effectCtrl:MakeBattleSkillEffectObj(effTrans, effRes, pos, LFightConst.DIRECTION_RIGHT, 0, playTime,dissipateTime)

    local para = {
        type = 2,
        isUpperLayer= player:IsUpperLayer(), -- player._isUpperLayer,
        scale = 1,
        changeScale = scaleV,
        skillId = skillId,
        skin = _skillData:GetTreasureSkin(),
        effType = effData.effType,
    }
    effect:SetEffectPara(para)
    effectCtrl:AddEffect(effect)
end

return LBattleSkillActTreasureIcon